$json = @'
{"d":""}
'@
$obj = $json | ConvertFrom-Json
$base64 = $obj.d
$m = [System.IO.MemoryStream][System.Convert]::FromBase64String($base64)
$decompressed = [System.IO.Compression.GZipStream]::new($m, [System.IO.Compression.CompressionMode]::Decompress).CopyTo([System.IO.MemoryStream]::new)
[System.Text.Encoding]::UTF8.GetString($decompressed.ToArray())